/// Test that `cache stats` returns all-zero buckets for an empty cache (raw output).
#[test]
fn cache_stats_empty_raw() {
    let context = uv_test::test_context!("3.12");
    context.clean().assert().success();

    uv_snapshot!(context.cache_stats().arg("--preview"), @"
    success: true
    exit_code: 0
    ----- stdout -----
    wheels-v6: 0
    sdists-v9: 0
    flat-index-v2: 0
    git-v0: 0
    interpreter-v4: 0
    simple-v21: 0
    archive-v0: 0
    builds-v0: 0
    environments-v2: 0
    binaries-v0: 0
    total: 0

    ----- stderr -----
    ");
}

/// Test that `cache stats` returns non-zero sizes after installing packages (raw output).
#[test]
fn cache_stats_with_packages_raw() {
    let context = uv_test::test_context!("3.12");
    context.pip_install().arg("iniconfig").assert().success();

    uv_snapshot!(context.with_filtered_cache_size().filters(), context.cache_stats().arg("--preview"), @"
    success: true
    exit_code: 0
    ----- stdout -----
    [CACHE_STATS]

    ----- stderr -----
    ");
}

/// Test that `cache stats --human` returns human-readable format.
#[test]
fn cache_stats_with_packages_human() {
    let context = uv_test::test_context!("3.12");
    context.pip_install().arg("iniconfig").assert().success();

    uv_snapshot!(context.with_filtered_cache_size().filters(), context.cache_stats().arg("--preview").arg("--human"), @"
    success: true
    exit_code: 0
    ----- stdout -----
    [CACHE_STATS]

    ----- stderr -----
    ");
}
```

> **Note on snapshot filtering**: The existing `with_filtered_cache_size()` filter matches `^\d+\n` (raw bytes on own line) and `^\d+(\.\d+)? [KMGT]i?B\n` (human-readable on own line). These won't match the `bucket: value` format. We'll need a new filter `with_filtered_cache_stats()` that matches lines like `bucket-name: \d+` and `bucket-name: \d+(\.\d+)? [KMGT]i?B`, replacing the full multi-line output with `[CACHE_STATS]`. Alternatively, we can add a broader filter or write the tests with inline snapshot expectations adjusted per-bucket. This detail will be refined during implementation — the empty-cache test can use exact snapshots (all zeros), and the populated tests need filtering.

## Verification

1. **Compile check**: Run `cargo check -p uv` to verify the code compiles
2. **Clippy**: Run `cargo clippy -p uv -p uv-cli -p uv-preview` to verify no lint warnings
3. **Unit tests**: Run `cargo test -p uv-preview` for the preview feature string tests
4. **Integration tests**: Run `cargo test -p uv --test it -- cache_stats` to run the new tests
5. **Manual smoke test**: Run `cargo run -p uv -- cache stats --preview` and `cargo run -p uv -- cache stats --preview --human` to verify output format

