    /// `--password` password.
    #[arg(
        short,
        long,
        env = EnvVars::UV_PUBLISH_TOKEN,
        hide_env_values = true,
        conflicts_with = "username",
        conflicts_with = "password",
        value_hint = ValueHint::Other,
    )]
