    /// Only install local path dependencies
    #[arg(
        long,
        conflicts_with = "frozen",
        conflicts_with = "no_sync",
        conflicts_with = "no_install_local",
        hide = true
    )]
    pub only_install_local: bool,

    /// Do not install the given package(s).
    ///
