12	/// Display per-bucket cache statistics.
13	pub(crate) fn cache_stats(
14	    cache: &Cache,
15	    human_readable: bool,
16	    printer: Printer,
17	    preview: Preview,
18	) -> Result<ExitStatus> {
19	    if !preview.is_enabled(PreviewFeature::CacheStats) {
20	        warn_user!(
21	            "`uv cache stats` is experimental and may change without warning. Pass `--preview-features {}` to disable this warning.",
22	            PreviewFeature::CacheStats
23	        );
24	    }
25	
26	    let mut total_bytes: u64 = 0;
27	
28	    for bucket in CacheBucket::iter() {
29	        let bucket_path = cache.bucket(bucket);
30	        let bucket_bytes = if bucket_path.exists() {
31	            let disk_usage = DiskUsage::new(vec![bucket_path]);
32	            disk_usage.count_ignoring_errors()
33	        } else {
34	            0
35	        };
36	
37	        total_bytes += bucket_bytes;
38	
39	        if human_readable {
40	            if bucket_bytes == 0 {
41	                writeln!(printer.stdout_important(), "{bucket}: 0B")?;
42	            } else {
43	                let (bytes, unit) = human_readable_bytes(bucket_bytes);
44	                writeln!(printer.stdout_important(), "{bucket}: {bytes:.1}{unit}")?;
45	            }
46	        } else {
47	            writeln!(printer.stdout_important(), "{bucket}: {bucket_bytes}")?;
48	        }
49	    }
50	
51	    if human_readable {
52	        if total_bytes == 0 {
53	            writeln!(printer.stdout_important(), "total: 0B")?;
54	        } else {
55	            let (bytes, unit) = human_readable_bytes(total_bytes);
56	            writeln!(printer.stdout_important(), "total: {bytes:.1}{unit}")?;
57	        }
58	    } else {
59	        writeln!(printer.stdout_important(), "total: {total_bytes}")?;
60	    }
61	
62	    Ok(ExitStatus::Success)
63	}
