126	/// Format a duration as a human-readable string, Cargo-style.
127	pub(super) fn elapsed(duration: Duration) -> String {
128	    let secs = duration.as_secs();
129	    let ms = duration.subsec_millis();
130	
131	    if secs >= 60 {
132	        format!("{}m {:02}s", secs / 60, secs % 60)
133	    } else if secs > 0 {
134	        format!("{}.{:02}s", secs, duration.subsec_nanos() / 10_000_000)
135	    } else if ms > 0 {
136	        format!("{ms}ms")
137	    } else {
138	        format!("0.{:02}ms", duration.subsec_nanos() / 10_000)
139	    }
140	}
